//! lwIP BSD socket networking for FreeRTOS.
//!
//! Implements PlatformTcp, PlatformUdp, PlatformSocketHelpers, and
//! PlatformUdpMulticast on FreeRtosPlatform using lwIP's BSD socket API.
//!
//! Types and constants are auto-generated by `freertos-lwip-sys` (bindgen),
//! eliminating manual struct size mismatches (e.g., newlib's 64-bit time_t).

#![allow(unsafe_op_in_unsafe_fn)]

use core::ffi::{c_int, c_void};

use crate::FreeRtosPlatform;
use freertos_lwip_sys::*;

// ============================================================================
// C struct wrappers matching zenoh-pico's FreeRTOS/lwIP platform types
// ============================================================================

/// Socket: `{ int _socket; }` (matches _z_sys_net_socket_t)
#[repr(C)]
struct Socket {
    _socket: c_int,
}

/// Endpoint: `{ struct addrinfo *_iptcp; }` (matches _z_sys_net_endpoint_t)
#[repr(C)]
struct Endpoint {
    _iptcp: *mut addrinfo,
}

/// Phase 71.22 — net buffer sizes (see nros-platform-posix for rationale).
pub const NET_SOCKET_SIZE: usize = core::mem::size_of::<Socket>();
pub const NET_SOCKET_ALIGN: usize = core::mem::align_of::<Socket>();
pub const NET_ENDPOINT_SIZE: usize = core::mem::size_of::<Endpoint>();
pub const NET_ENDPOINT_ALIGN: usize = core::mem::align_of::<Endpoint>();

const Z_TRANSPORT_LEASE: u32 = 10000; // ms

// ============================================================================
// TCP
// ============================================================================

impl FreeRtosPlatform {
    pub fn tcp_create_endpoint(ep: *mut c_void, address: *const u8, port: *const u8) -> i8 {
        unsafe { lwip_socket_thread_init() };
        let ep = ep as *mut Endpoint;

        let mut hints: addrinfo = unsafe { core::mem::zeroed() };
        hints.ai_family = PF_UNSPEC as c_int;
        hints.ai_socktype = SOCK_STREAM as c_int;
        hints.ai_protocol = IPPROTO_TCP as c_int;

        let ret = unsafe {
            lwip_getaddrinfo(
                address as *const _,
                port as *const _,
                &hints,
                &mut (*ep)._iptcp,
            )
        };
        if ret != 0 {
            return -1;
        }

        // lwIP quirk: getaddrinfo doesn't always set sa_family on the sockaddr.
        // The C code does: ep->_iptcp->ai_addr->sa_family = ep->_iptcp->ai_family;
        unsafe {
            let ai = &*(*ep)._iptcp;
            if !ai.ai_addr.is_null() {
                (*ai.ai_addr).sa_family = ai.ai_family as u8;
            }
        }
        0
    }

    pub fn tcp_free_endpoint(ep: *mut c_void) {
        let ep = ep as *mut Endpoint;
        unsafe {
            if !(*ep)._iptcp.is_null() {
                lwip_freeaddrinfo((*ep)._iptcp);
            }
        }
    }

    pub fn tcp_open(sock: *mut c_void, endpoint: *const c_void, timeout_ms: u32) -> i8 {
        unsafe { lwip_socket_thread_init() };

        let sock = sock as *mut Socket;
        let rep = unsafe { &*(endpoint as *const Endpoint) };

        if rep._iptcp.is_null() {
            return -1;
        }
        let ai = unsafe { &*rep._iptcp };

        // Fix sa_family if not set
        unsafe {
            if !ai.ai_addr.is_null() && (*ai.ai_addr).sa_family == 0 {
                (*ai.ai_addr).sa_family = ai.ai_family as u8;
            }
        }

        let fd = unsafe { lwip_socket(ai.ai_family, ai.ai_socktype, ai.ai_protocol) };
        if fd < 0 {
            return -1;
        }
        unsafe { (*sock)._socket = fd };

        // SO_RCVTIMEO
        let tv = timeval {
            tv_sec: (timeout_ms / 1000) as _,
            tv_usec: ((timeout_ms % 1000) * 1000) as _,
        };
        if unsafe {
            lwip_setsockopt(
                fd,
                SOL_SOCKET as c_int,
                SO_RCVTIMEO as c_int,
                &tv as *const _ as *const c_void,
                core::mem::size_of::<timeval>() as u32,
            )
        } < 0
        {
            unsafe { lwip_close(fd) };
            return -1;
        }

        // SO_SNDTIMEO (lwIP blocks on send when congestion window closes)
        unsafe {
            lwip_setsockopt(
                fd,
                SOL_SOCKET as c_int,
                SO_SNDTIMEO as c_int,
                &tv as *const _ as *const c_void,
                core::mem::size_of::<timeval>() as u32,
            );
        }

        // SO_KEEPALIVE
        let one: c_int = 1;
        unsafe {
            lwip_setsockopt(
                fd,
                SOL_SOCKET as c_int,
                SO_KEEPALIVE as c_int,
                &one as *const _ as *const c_void,
                4,
            );
        }

        // TCP_NODELAY
        unsafe {
            lwip_setsockopt(
                fd,
                IPPROTO_TCP as c_int,
                TCP_NODELAY as c_int,
                &one as *const _ as *const c_void,
                4,
            );
        }

        // SO_LINGER
        let ling = linger {
            l_onoff: 1,
            l_linger: (Z_TRANSPORT_LEASE / 1000) as c_int,
        };
        unsafe {
            lwip_setsockopt(
                fd,
                SOL_SOCKET as c_int,
                SO_LINGER as c_int,
                &ling as *const _ as *const c_void,
                core::mem::size_of::<linger>() as u32,
            );
        }

        // Connect — iterate through addrinfo list
        let mut it = rep._iptcp;
        while !it.is_null() {
            let ai = unsafe { &*it };
            let ret = unsafe { lwip_connect(fd, ai.ai_addr, ai.ai_addrlen) };
            if ret == 0 {
                return 0;
            }
            it = ai.ai_next;
        }

        unsafe {
            lwip_close(fd);
            (*sock)._socket = -1;
        }
        -1
    }

    pub fn tcp_listen(sock: *mut c_void, endpoint: *const c_void) -> i8 {
        unsafe { lwip_socket_thread_init() };

        let sock = sock as *mut Socket;
        let rep = unsafe { &*(endpoint as *const Endpoint) };

        let ai = unsafe { &*rep._iptcp };
        let fd = unsafe { lwip_socket(ai.ai_family, ai.ai_socktype, ai.ai_protocol) };
        if fd < 0 {
            return -1;
        }

        let one: c_int = 1;
        unsafe {
            lwip_setsockopt(
                fd,
                SOL_SOCKET as c_int,
                SO_REUSEADDR as c_int,
                &one as *const _ as *const c_void,
                4,
            );
        }

        if unsafe { lwip_bind(fd, ai.ai_addr, ai.ai_addrlen) } < 0 {
            unsafe { lwip_close(fd) };
            return -1;
        }

        if unsafe { lwip_listen(fd, 1) } < 0 {
            unsafe { lwip_close(fd) };
            return -1;
        }

        let tv = timeval {
            tv_sec: (Z_TRANSPORT_LEASE / 1000) as _,
            tv_usec: 0 as _,
        };
        unsafe {
            lwip_setsockopt(
                fd,
                SOL_SOCKET as c_int,
                SO_RCVTIMEO as c_int,
                &tv as *const _ as *const c_void,
                core::mem::size_of::<timeval>() as u32,
            );
        }

        unsafe { (*sock)._socket = fd };
        0
    }

    pub fn tcp_close(sock: *mut c_void) {
        unsafe { lwip_socket_thread_init() };
        let sock = sock as *mut Socket;
        let fd = unsafe { (*sock)._socket };
        if fd >= 0 {
            unsafe {
                lwip_shutdown(fd, SHUT_RDWR as c_int);
                lwip_close(fd);
                (*sock)._socket = -1;
            }
        }
    }

    pub fn tcp_read(sock: *const c_void, buf: *mut u8, len: usize) -> usize {
        unsafe { lwip_socket_thread_init() };
        let sock = unsafe { &*(sock as *const Socket) };
        if sock._socket < 0 {
            return usize::MAX;
        }
        let n = unsafe { lwip_recv(sock._socket, buf as *mut c_void, len, 0) };
        if n <= 0 { usize::MAX } else { n as usize }
    }

    pub fn tcp_read_exact(sock: *const c_void, buf: *mut u8, len: usize) -> usize {
        unsafe { lwip_socket_thread_init() };
        let sock = unsafe { &*(sock as *const Socket) };
        if sock._socket < 0 {
            return usize::MAX;
        }

        let mut total: usize = 0;
        while total < len {
            let n =
                unsafe { lwip_recv(sock._socket, buf.add(total) as *mut c_void, len - total, 0) };
            if n <= 0 {
                return usize::MAX;
            }
            total += n as usize;
        }
        total
    }

    pub fn tcp_send(sock: *const c_void, buf: *const u8, len: usize) -> usize {
        unsafe { lwip_socket_thread_init() };
        let sock = unsafe { &*(sock as *const Socket) };
        if sock._socket < 0 {
            return usize::MAX;
        }

        let mut total: usize = 0;
        while total < len {
            let n = unsafe {
                lwip_send(
                    sock._socket,
                    buf.add(total) as *const c_void,
                    len - total,
                    0,
                )
            };
            if n <= 0 {
                return usize::MAX;
            }
            total += n as usize;
        }
        total
    }
}

// ============================================================================
// UDP
// ============================================================================

impl FreeRtosPlatform {
    pub fn udp_create_endpoint(ep: *mut c_void, address: *const u8, port: *const u8) -> i8 {
        unsafe { lwip_socket_thread_init() };
        let ep = ep as *mut Endpoint;

        let mut hints: addrinfo = unsafe { core::mem::zeroed() };
        hints.ai_family = PF_UNSPEC as c_int;
        hints.ai_socktype = SOCK_DGRAM as c_int;
        hints.ai_protocol = IPPROTO_UDP as c_int;

        let ret = unsafe {
            lwip_getaddrinfo(
                address as *const _,
                port as *const _,
                &hints,
                &mut (*ep)._iptcp,
            )
        };
        if ret != 0 {
            return -1;
        }

        // lwIP quirk: copy ai_family to sa_family
        unsafe {
            let ai = &*(*ep)._iptcp;
            if !ai.ai_addr.is_null() {
                (*ai.ai_addr).sa_family = ai.ai_family as u8;
            }
        }
        0
    }

    pub fn udp_free_endpoint(ep: *mut c_void) {
        Self::tcp_free_endpoint(ep)
    }

    pub fn udp_open(sock: *mut c_void, endpoint: *const c_void, timeout_ms: u32) -> i8 {
        unsafe { lwip_socket_thread_init() };

        let sock = sock as *mut Socket;
        let rep = unsafe { &*(endpoint as *const Endpoint) };

        let ai = unsafe { &*rep._iptcp };
        let fd = unsafe { lwip_socket(ai.ai_family, ai.ai_socktype, ai.ai_protocol) };
        if fd < 0 {
            return -1;
        }
        unsafe { (*sock)._socket = fd };

        let tv = timeval {
            tv_sec: (timeout_ms / 1000) as _,
            tv_usec: ((timeout_ms % 1000) * 1000) as _,
        };
        unsafe {
            lwip_setsockopt(
                fd,
                SOL_SOCKET as c_int,
                SO_RCVTIMEO as c_int,
                &tv as *const _ as *const c_void,
                core::mem::size_of::<timeval>() as u32,
            );
        }

        0
    }

    /// Phase 71.21 — bind a UDP socket for inbound use via lwIP.
    pub fn udp_listen(sock: *mut c_void, endpoint: *const c_void, timeout_ms: u32) -> i8 {
        unsafe { lwip_socket_thread_init() };

        let sock = sock as *mut Socket;
        let rep = unsafe { &*(endpoint as *const Endpoint) };
        let ai = unsafe { &*rep._iptcp };

        let fd = unsafe { lwip_socket(ai.ai_family, ai.ai_socktype, ai.ai_protocol) };
        if fd < 0 {
            return -1;
        }
        unsafe { (*sock)._socket = fd };

        let one: c_int = 1;
        unsafe {
            lwip_setsockopt(
                fd,
                SOL_SOCKET as c_int,
                SO_REUSEADDR as c_int,
                &one as *const _ as *const c_void,
                core::mem::size_of::<c_int>() as u32,
            );
        }

        let tv = timeval {
            tv_sec: (timeout_ms / 1000) as _,
            tv_usec: ((timeout_ms % 1000) * 1000) as _,
        };
        unsafe {
            lwip_setsockopt(
                fd,
                SOL_SOCKET as c_int,
                SO_RCVTIMEO as c_int,
                &tv as *const _ as *const c_void,
                core::mem::size_of::<timeval>() as u32,
            );
        }

        if unsafe { lwip_bind(fd, ai.ai_addr, ai.ai_addrlen) } < 0 {
            unsafe { lwip_close(fd) };
            unsafe { (*sock)._socket = -1 };
            return -1;
        }
        0
    }

    pub fn udp_close(sock: *mut c_void) {
        unsafe { lwip_socket_thread_init() };
        let sock = sock as *mut Socket;
        let fd = unsafe { (*sock)._socket };
        if fd >= 0 {
            unsafe {
                lwip_close(fd);
                (*sock)._socket = -1;
            }
        }
    }

    pub fn udp_read(sock: *const c_void, buf: *mut u8, len: usize) -> usize {
        unsafe { lwip_socket_thread_init() };
        let sock = unsafe { &*(sock as *const Socket) };
        if sock._socket < 0 {
            return usize::MAX;
        }
        let n = unsafe {
            lwip_recvfrom(
                sock._socket,
                buf as *mut c_void,
                len,
                0,
                core::ptr::null_mut(),
                core::ptr::null_mut(),
            )
        };
        if n <= 0 { usize::MAX } else { n as usize }
    }

    pub fn udp_read_exact(sock: *const c_void, buf: *mut u8, len: usize) -> usize {
        // UDP is datagram-based — read_exact reads one datagram
        Self::udp_read(sock, buf, len)
    }

    pub fn udp_send(
        sock: *const c_void,
        buf: *const u8,
        len: usize,
        endpoint: *const c_void,
    ) -> usize {
        unsafe { lwip_socket_thread_init() };
        let sock = unsafe { &*(sock as *const Socket) };
        let rep = unsafe { &*(endpoint as *const Endpoint) };
        if sock._socket < 0 || rep._iptcp.is_null() {
            return usize::MAX;
        }
        let ai = unsafe { &*rep._iptcp };
        let n = unsafe {
            lwip_sendto(
                sock._socket,
                buf as *const c_void,
                len,
                0,
                ai.ai_addr,
                ai.ai_addrlen,
            )
        };
        if n <= 0 { usize::MAX } else { n as usize }
    }

    pub fn udp_set_recv_timeout(sock: *const c_void, timeout_ms: u32) {
        unsafe { lwip_socket_thread_init() };
        let sock = unsafe { &*(sock as *const Socket) };
        // lwIP's `SO_RCVTIMEO` with `{0, 0}` means "no timeout — block
        // forever". Cooperative DDS recv loops (Phase 71.2) call this
        // with `0` to mean non-blocking; honour that via fcntl.
        if timeout_ms == 0 {
            unsafe {
                let flags = lwip_fcntl(sock._socket, F_GETFL as c_int, 0);
                if flags >= 0 {
                    lwip_fcntl(sock._socket, F_SETFL as c_int, flags | O_NONBLOCK as c_int);
                }
            }
            return;
        }
        let tv = timeval {
            tv_sec: (timeout_ms / 1000) as _,
            tv_usec: ((timeout_ms % 1000) * 1000) as _,
        };
        unsafe {
            lwip_setsockopt(
                sock._socket,
                SOL_SOCKET as c_int,
                SO_RCVTIMEO as c_int,
                &tv as *const _ as *const c_void,
                core::mem::size_of::<timeval>() as u32,
            );
        }
    }
}

// ============================================================================
// Socket helpers
// ============================================================================

impl FreeRtosPlatform {
    pub fn socket_set_non_blocking(sock: *const c_void) -> i8 {
        unsafe { lwip_socket_thread_init() };
        let sock = unsafe { &*(sock as *const Socket) };
        let flags = unsafe { lwip_fcntl(sock._socket, F_GETFL as c_int, 0) };
        if flags < 0 {
            return -1;
        }
        if unsafe { lwip_fcntl(sock._socket, F_SETFL as c_int, flags | O_NONBLOCK as c_int) } < 0 {
            return -1;
        }
        0
    }

    pub fn socket_accept(sock_in: *const c_void, sock_out: *mut c_void) -> i8 {
        unsafe { lwip_socket_thread_init() };
        let sin = unsafe { &*(sock_in as *const Socket) };
        let sout = sock_out as *mut Socket;
        let mut addr: sockaddr = unsafe { core::mem::zeroed() };
        let mut addrlen: u32 = core::mem::size_of::<sockaddr>() as u32;

        let fd = unsafe { lwip_accept(sin._socket, &mut addr, &mut addrlen) };
        if fd < 0 {
            return -1;
        }

        // Set timeout + options on accepted socket
        let tv = timeval {
            tv_sec: (Z_TRANSPORT_LEASE / 1000) as _,
            tv_usec: 0 as _,
        };
        unsafe {
            lwip_setsockopt(
                fd,
                SOL_SOCKET as c_int,
                SO_RCVTIMEO as c_int,
                &tv as *const _ as *const c_void,
                core::mem::size_of::<timeval>() as u32,
            );
            let one: c_int = 1;
            lwip_setsockopt(
                fd,
                SOL_SOCKET as c_int,
                SO_KEEPALIVE as c_int,
                &one as *const _ as *const c_void,
                4,
            );
            lwip_setsockopt(
                fd,
                IPPROTO_TCP as c_int,
                TCP_NODELAY as c_int,
                &one as *const _ as *const c_void,
                4,
            );
            let ling = linger {
                l_onoff: 1,
                l_linger: (Z_TRANSPORT_LEASE / 1000) as c_int,
            };
            lwip_setsockopt(
                fd,
                SOL_SOCKET as c_int,
                SO_LINGER as c_int,
                &ling as *const _ as *const c_void,
                core::mem::size_of::<linger>() as u32,
            );
            (*sout)._socket = fd;
        }
        0
    }

    pub fn socket_close(sock: *mut c_void) {
        Self::tcp_close(sock);
    }

    pub fn socket_wait_event(_peers: *mut c_void, _mutex: *mut c_void) -> i8 {
        // Phase 77.22: delegate to the unified `PlatformYield::yield_now()`.
        use nros_platform_api::PlatformYield;
        <Self as PlatformYield>::yield_now();
        0
    }
}

/// Parse a NUL-terminated dotted-quad ASCII IPv4 address (e.g.
/// `b"239.255.0.1\0"`) into a host-byte-order u32. Returns `None` on
/// malformed input.
fn parse_dotted_quad_le(s: *const u8) -> Option<u32> {
    if s.is_null() {
        return None;
    }
    // SAFETY: caller must pass a NUL-terminated string; bound the
    // search at 16 bytes (max IPv4 dotted-quad length is 15 + NUL).
    let bytes: &[u8] = unsafe {
        let mut len = 0usize;
        while len < 16 {
            if *s.add(len) == 0 {
                break;
            }
            len += 1;
        }
        core::slice::from_raw_parts(s, len)
    };
    let mut octets = [0u32; 4];
    let mut idx = 0usize;
    let mut cur: u32 = 0;
    let mut have_digit = false;
    for &b in bytes {
        match b {
            b'0'..=b'9' => {
                cur = cur.wrapping_mul(10).wrapping_add((b - b'0') as u32);
                if cur > 255 {
                    return None;
                }
                have_digit = true;
            }
            b'.' => {
                if !have_digit || idx >= 3 {
                    return None;
                }
                octets[idx] = cur;
                idx += 1;
                cur = 0;
                have_digit = false;
            }
            _ => return None,
        }
    }
    if !have_digit || idx != 3 {
        return None;
    }
    octets[3] = cur;
    Some((octets[0] << 24) | (octets[1] << 16) | (octets[2] << 8) | octets[3])
}

// ============================================================================
// UDP multicast (Phase 97.4.freertos: IGMP join via lwIP setsockopt)
// ============================================================================

impl FreeRtosPlatform {
    pub fn mcast_open(
        _sock: *mut c_void,
        _endpoint: *const c_void,
        _lep: *mut c_void,
        _timeout_ms: u32,
        _iface: *const u8,
    ) -> i8 {
        -1
    }

    /// Open a UDP socket bound to `INADDR_ANY:port` (port from
    /// `endpoint`) and join the multicast group `join` (NUL-terminated
    /// dotted-quad ASCII, e.g. `b"239.255.0.1\0"`).
    ///
    /// Mirrors the POSIX impl in `nros-platform-posix::net::mcast_listen`
    /// but uses lwIP's BSD socket API. Requires `LWIP_IGMP=1` in
    /// `lwipopts.h` (Phase 97.1.kconfig.freertos enables it).
    pub fn mcast_listen(
        sock: *mut c_void,
        endpoint: *const c_void,
        timeout_ms: u32,
        _iface: *const u8,
        join: *const u8,
    ) -> i8 {
        unsafe { lwip_socket_thread_init() };

        let sock = sock as *mut Socket;
        let rep = unsafe { &*(endpoint as *const Endpoint) };
        let ai = unsafe { &*rep._iptcp };

        // Only IPv4 supported (lwIP's IGMP is IPv4-only).
        if ai.ai_family != AF_INET as c_int {
            return -1;
        }

        let fd = unsafe { lwip_socket(ai.ai_family, ai.ai_socktype, ai.ai_protocol) };
        if fd < 0 {
            return -1;
        }
        unsafe { (*sock)._socket = fd };

        let one: c_int = 1;
        let tv = timeval {
            tv_sec: (timeout_ms / 1000) as _,
            tv_usec: ((timeout_ms % 1000) * 1000) as _,
        };
        unsafe {
            lwip_setsockopt(
                fd,
                SOL_SOCKET as c_int,
                SO_REUSEADDR as c_int,
                &one as *const _ as *const c_void,
                core::mem::size_of::<c_int>() as u32,
            );
            lwip_setsockopt(
                fd,
                SOL_SOCKET as c_int,
                SO_RCVTIMEO as c_int,
                &tv as *const _ as *const c_void,
                core::mem::size_of::<timeval>() as u32,
            );
        }

        // Bind to INADDR_ANY:port. `ai.ai_addr` from getaddrinfo on
        // "0.0.0.0" already has sin_addr = 0; we just need to ensure
        // sa_family is set (the `udp_create_endpoint` quirk handler
        // does this earlier in the path).
        if unsafe { lwip_bind(fd, ai.ai_addr, ai.ai_addrlen) } < 0 {
            unsafe {
                lwip_close(fd);
                (*sock)._socket = -1;
            }
            return -1;
        }

        // Parse `join` (NUL-terminated dotted-quad ASCII) into 32-bit
        // network-order address, then setsockopt(IP_ADD_MEMBERSHIP).
        let group_addr = match parse_dotted_quad_le(join) {
            Some(host) => host.to_be(),
            None => {
                unsafe {
                    lwip_close(fd);
                    (*sock)._socket = -1;
                }
                return -1;
            }
        };
        let mreq = ip_mreq {
            imr_multiaddr: in_addr { s_addr: group_addr },
            imr_interface: in_addr {
                s_addr: 0u32, // INADDR_ANY — let lwIP pick the netif
            },
        };
        let join_rc = unsafe {
            lwip_setsockopt(
                fd,
                IPPROTO_IP as c_int,
                IP_ADD_MEMBERSHIP as c_int,
                &mreq as *const _ as *const c_void,
                core::mem::size_of::<ip_mreq>() as u32,
            )
        };
        if join_rc < 0 {
            unsafe {
                lwip_close(fd);
                (*sock)._socket = -1;
            }
            return -1;
        }
        0
    }

    pub fn mcast_close(
        sockrecv: *mut c_void,
        socksend: *mut c_void,
        _rep: *const c_void,
        _lep: *const c_void,
    ) {
        if !sockrecv.is_null() {
            Self::udp_close(sockrecv);
        }
        if !socksend.is_null() && socksend != sockrecv {
            Self::udp_close(socksend);
        }
    }

    /// Receive a datagram on a multicast socket. The socket is the
    /// one returned by `mcast_listen`, so this is just `recvfrom`.
    pub fn mcast_read(
        sock: *const c_void,
        buf: *mut u8,
        len: usize,
        _lep: *const c_void,
        _addr: *mut c_void,
    ) -> usize {
        unsafe { lwip_socket_thread_init() };
        let sock = sock as *const Socket;
        let fd = unsafe { (*sock)._socket };
        if fd < 0 {
            return usize::MAX;
        }
        // Non-blocking recv (the listen path set SO_RCVTIMEO=0).
        let n = unsafe {
            lwip_recvfrom(
                fd,
                buf as *mut c_void,
                len,
                0,
                core::ptr::null_mut(),
                core::ptr::null_mut(),
            )
        };
        if n < 0 { 0 } else { n as usize }
    }

    pub fn mcast_read_exact(
        _sock: *const c_void,
        _buf: *mut u8,
        _len: usize,
        _lep: *const c_void,
        _addr: *mut c_void,
    ) -> usize {
        usize::MAX
    }

    /// Send a datagram to a multicast group. `endpoint` is the
    /// dotted-quad + port the group joiners are listening on.
    pub fn mcast_send(
        sock: *const c_void,
        buf: *const u8,
        len: usize,
        endpoint: *const c_void,
    ) -> usize {
        unsafe { lwip_socket_thread_init() };
        let sock = sock as *const Socket;
        let fd = unsafe { (*sock)._socket };
        if fd < 0 {
            return usize::MAX;
        }
        let rep = unsafe { &*(endpoint as *const Endpoint) };
        let ai = unsafe { &*rep._iptcp };
        let n = unsafe { lwip_sendto(fd, buf as *const c_void, len, 0, ai.ai_addr, ai.ai_addrlen) };
        if n < 0 { usize::MAX } else { n as usize }
    }
}

// ============================================================================
// Trait impls (Phase 84.F4.4)
// ============================================================================
//
// Delegate to the inherent methods above. Every shim dispatch goes through
// these traits (`<ConcretePlatform as PlatformTcp>::open(...)`) so a
// trait-method rename or addition produces a compile error here instead of
// a silent link failure. The inherent methods are kept (rather than
// collapsed into the trait bodies) so that internal `Self::tcp_read` /
// `Self::udp_send` / ... calls in this file keep working unchanged.

impl nros_platform_api::PlatformTcp for FreeRtosPlatform {
    fn create_endpoint(ep: *mut c_void, address: *const u8, port: *const u8) -> i8 {
        Self::tcp_create_endpoint(ep, address, port)
    }
    fn free_endpoint(ep: *mut c_void) {
        Self::tcp_free_endpoint(ep)
    }
    fn open(sock: *mut c_void, endpoint: *const c_void, timeout_ms: u32) -> i8 {
        Self::tcp_open(sock, endpoint, timeout_ms)
    }
    fn listen(sock: *mut c_void, endpoint: *const c_void) -> i8 {
        Self::tcp_listen(sock, endpoint)
    }
    fn close(sock: *mut c_void) {
        Self::tcp_close(sock)
    }
    fn read(sock: *const c_void, buf: *mut u8, len: usize) -> usize {
        Self::tcp_read(sock, buf, len)
    }
    fn read_exact(sock: *const c_void, buf: *mut u8, len: usize) -> usize {
        Self::tcp_read_exact(sock, buf, len)
    }
    fn send(sock: *const c_void, buf: *const u8, len: usize) -> usize {
        Self::tcp_send(sock, buf, len)
    }
}

